(window.webpackJsonp=window.webpackJsonp||[]).push([[67],{1773:function(e){e.exports=JSON.parse('{"content":"<p><code>threejs</code>\u521d\u4f53\u9a8c\uff0c\u5173\u4e8e<code>3D</code>\u6e32\u67d3\uff0c\u81ea\u7136\u4f1a\u6d89\u53ca\u5230\u5927\u91cf\u6570\u5b66\u8ba1\u7b97\uff0c\u7b97\u6cd5\u516c\u5f0f\uff0c\u4f46\u8fd9\u4e9b<code>threejs</code>\u5df2\u7ecf\u5c01\u88c5\u4e86\uff0c\u76f4\u63a5\u8c03\u7528<code>API</code>\u5373\u53ef\u5b8c\u6210\u5927\u91cf\u5de5\u4f5c\u3002</p>\\n<p><code>threejs</code>\u7528\u53f3\u624b\u5750\u6807\u7cfb\uff0c\u5373\u4e0a<code>y</code>\uff0c\u53f3<code>x</code>\uff0c<code>z</code>\u8f74\u4ece\u5c4f\u5e55\u91cc\u5230\u5916</p>\\n<p><code>3D</code>\u6e32\u67d3\u6d89\u53ca\u6982\u5ff5</p>\\n<ol>\\n<li>\u573a\u666f</li>\\n</ol>\\n<p>\u6307\u4f60\u60f3\u5c55\u793a\u7ed9\u522b\u4eba\u770b\u5230\u4e1c\u897f\u603b\u79f0\uff0c\u4f60\u60f3\u5c55\u793a\uff0c\u9700\u8981\u6dfb\u52a0\u5230\u573a\u666f\uff0c\u4e0d\u60f3\u5c55\u793a\uff0c\u9700\u8981\u4ece\u573a\u666f\u4e2d\u5220\u9664\u3002</p>\\n<ol start=\\"2\\">\\n<li>\u6444\u50cf\u673a</li>\\n</ol>\\n<p>\u6307\u7528\u6237\u7684\u89c6\u89d2\uff0c\u5982\u679c\u7528\u6237\u60f3\u770b\u7269\u4f53\u7684\u540e\u9762\uff0c\u610f\u601d\u5c31\u662f\u6444\u50cf\u673a\u8f6c\u5230\u7269\u4f53\u540e\u9762\uff0c<code>three-orbitcontrols</code>\u5df2\u7ecf\u4e3a\u6211\u4eec\u5c01\u88c5\u4e86\u6444\u50cf\u673a\u7684\u9f20\u6807\u64cd\u63a7\u3002</p>\\n<ol start=\\"3\\">\\n<li>\u51e0\u4f55\u4f53(Geometry)</li>\\n</ol>\\n<p>\u6307\u4e00\u4e9b\u5f62\u72b6\u7269\u4f53\uff0c\u5982\u7403\u4f53\uff0c\u6b63\u65b9\u4f53\uff0c\u5706\u9525\uff0c\u7ba1\u9053\u7b49\u7b49\uff0c<code>threejs</code>\u63d0\u4f9b\u591a\u79cd\u53ef\u4ee5\u76f4\u63a5\u8c03\u7528\u7684\u5f62\u72b6\u3002</p>\\n<ol start=\\"4\\">\\n<li>\u6750\u8d28(Material)</li>\\n</ol>\\n<p>\u6307\u7269\u4f53\u8868\u9762\u7684\u989c\u8272\uff0c\u5149\u4eae\uff0c\u81ea\u5b9a\u4e49\u76ae\u80a4(\u7eb9\u7406\uff09\u7b49</p>\\n<ol start=\\"5\\">\\n<li>Mesh</li>\\n</ol>\\n<p>\u4e00\u822c\u6765\u8bb2\uff0c<code>Mesh</code> \u7531 <code>Geometry</code> + <code>Material</code> \u7ec4\u5408\u800c\u6210\uff0c\u60f3\u8c61\u4e00\u4e0b\uff0c\u73b0\u5728<code>\u51e0\u4f55\u4f53</code>\u6709\u6b63\u65b9\u4f53\u548c\u7403\u4f53\uff0c <code>\u6750\u8d28</code>\u6709\u7ea2\u8272\u548c\u84dd\u8272\uff0c\\n\u90a3\u4e48<code>Mesh</code>\u80fd\u7ec4\u5408\u51fa\u7ea2\u8272\u6b63\u65b9\u4f53\uff0c\u84dd\u8272\u6b63\u65b9\u4f53\uff0c\u7ea2\u8272\u7403\u4f53\uff0c\u84dd\u8272\u7403\u4f53</p>\\n<ol start=\\"6\\">\\n<li>Group</li>\\n</ol>\\n<p>\u5f53\u4f60\u521b\u5efa\u4e86\u591a\u4e2a<code>Mesh</code>\u540e\uff0c\u53ef\u4ee5\u7528Group\u5305\u88f9\u90e8\u5206\uff0c\u4ece\u800c\u5f62\u6210\u4e00\u4e2a\u6574\u4f53\uff0c\u9762\u5bf9\u79fb\u52a8\uff0c\u65cb\u8f6c\u7b49\u52a8\u753b\u6548\u679c\uff0c\u53ef\u4ee5\u6574\u4f53\u800c\u52a8</p>\\n<h4>\u6700\u7b80\u5355\u7684\u521b\u5efa\u4e00\u4e2a\u7269\u4f53</h4>\\n<pre class=\\"hljs\\"><code><span class=\\"hljs-keyword\\">let</span> boxGeo=<span class=\\"hljs-keyword\\">new</span> THREE.BoxBufferGeometry(width,height,depth)\\n<span class=\\"hljs-keyword\\">let</span> boxMat=<span class=\\"hljs-keyword\\">new</span> THREE.MeshStandardMaterial({\\n             <span class=\\"hljs-attr\\">color</span>: <span class=\\"hljs-string\\">\'#000000\'</span>,\\n             <span class=\\"hljs-attr\\">roughness</span>:<span class=\\"hljs-number\\">1</span>, <span class=\\"hljs-comment\\">// \u5149\u6ed1\u7684\u9762</span>\\n           })\\n<span class=\\"hljs-keyword\\">let</span> boxObj=<span class=\\"hljs-keyword\\">new</span> THREE.Mesh( boxGeo, boxMat )\\n</code></pre>\\n"}')}}]);